        public void Deal3DFuncNew(HObject ho_Image, HTuple hv_SampleDistance, HTuple hv_valueDistance,
      HTuple hv_yInterval, out HTuple hv_Sample3DModule)
        {




            // Local iconic variables 

            HObject ho_Bx, ho_By, ho_Bz;

            // Local control variables 

            HTuple hv_Sample3DModuleTmp = new HTuple();
            HTuple hv_ObjectModel3DBLeft = new HTuple(), hv_ObjectModel3DBLeftConnected = new HTuple();
            HTuple hv_ObjectModel3DBLeftNew = new HTuple(), hv_Info = new HTuple();
            // Initialize local and output iconic variables 
            HOperatorSet.GenEmptyObj(out ho_Bx);
            HOperatorSet.GenEmptyObj(out ho_By);
            HOperatorSet.GenEmptyObj(out ho_Bz);
            hv_Sample3DModule = new HTuple();
            try
            {

                //sample_object_model_3d (Tmp3DModule, 'fast_compute_normals', 0.12, [], [], Sample3DModuleTmp)
                ho_Bx.Dispose(); ho_By.Dispose(); ho_Bz.Dispose(); hv_ObjectModel3DBLeft.Dispose();
                Creat_XYZ_From_sszn_COPY_New(ho_Image, out ho_Bx, out ho_By, out ho_Bz, hv_yInterval,
                    out hv_ObjectModel3DBLeft);
                hv_ObjectModel3DBLeftConnected.Dispose();
                HOperatorSet.ConnectionObjectModel3d(hv_ObjectModel3DBLeft, "distance_3d",
                    hv_valueDistance, out hv_ObjectModel3DBLeftConnected);
                hv_ObjectModel3DBLeftNew.Dispose();
                HOperatorSet.SelectObjectModel3d(hv_ObjectModel3DBLeftConnected, "num_points",
                    "and", 200000, 1e100, out hv_ObjectModel3DBLeftNew);

                using (HDevDisposeHelper dh = new HDevDisposeHelper())
                {
                    hv_Sample3DModuleTmp.Dispose();
                    HOperatorSet.SampleObjectModel3d(hv_ObjectModel3DBLeftNew.TupleSelect(0), "fast_compute_normals",
                        hv_SampleDistance, new HTuple(), new HTuple(), out hv_Sample3DModuleTmp);
                }
                hv_Sample3DModule.Dispose(); hv_Info.Dispose();
                HOperatorSet.TriangulateObjectModel3d(hv_Sample3DModuleTmp, "greedy", new HTuple(),
                    new HTuple(), out hv_Sample3DModule, out hv_Info);
                ho_Bx.Dispose();
                ho_By.Dispose();
                ho_Bz.Dispose();

                hv_Sample3DModuleTmp.Dispose();
                hv_ObjectModel3DBLeft.Dispose();
                hv_ObjectModel3DBLeftConnected.Dispose();
                hv_ObjectModel3DBLeftNew.Dispose();
                hv_Info.Dispose();

                return;
            }
            catch (HalconException HDevExpDefaultException)
            {
                ho_Bx.Dispose();
                ho_By.Dispose();
                ho_Bz.Dispose();

                hv_Sample3DModuleTmp.Dispose();
                hv_ObjectModel3DBLeft.Dispose();
                hv_ObjectModel3DBLeftConnected.Dispose();
                hv_ObjectModel3DBLeftNew.Dispose();
                hv_Info.Dispose();

            }
        }
        public void Deal3DFunc(HTuple hv_Tmp3DModule, HTuple hv_SampleDistance, out HTuple hv_Sample3DModule)
        {



            // Local control variables 

            HTuple hv_Sample3DModuleTmp = new HTuple();
            HTuple hv_Info = new HTuple();
            // Initialize local and output iconic variables 
            hv_Sample3DModule = new HTuple();
            try
            {

                //sample_object_model_3d (Tmp3DModule, 'fast_compute_normals', 0.12, [], [], Sample3DModuleTmp)
                hv_Sample3DModuleTmp.Dispose();
                HOperatorSet.SampleObjectModel3d(hv_Tmp3DModule, "fast_compute_normals", hv_SampleDistance,
                    new HTuple(), new HTuple(), out hv_Sample3DModuleTmp);
                hv_Sample3DModule.Dispose(); hv_Info.Dispose();
                HOperatorSet.TriangulateObjectModel3d(hv_Sample3DModuleTmp, "greedy", new HTuple(),
                    new HTuple(), out hv_Sample3DModule, out hv_Info);

                hv_Sample3DModuleTmp.Dispose();
                hv_Info.Dispose();

                return;
            }
            catch (HalconException HDevExpDefaultException)
            {

                hv_Sample3DModuleTmp.Dispose();
                hv_Info.Dispose();

            }
        }
